from pathlib import Path
import re

def explain_time(expr: str) -> str:
    e = expr.replace(' ', '')
    if e in {'O(1)', 'O（1）'}:
        return '，因为核心操作与输入规模无关。'
    if 'log' in expr:
        return '，主要开销来自排序/二分/堆等对数级操作。'
    if 'mn' in e or ('m' in e and 'n' in e and '*' in e):
        return '，因为需要遍历二维规模数据。'
    if 'n³' in e or 'n^3' in e:
        return '，通常来自三重循环或三维状态转移。'
    if 'n²' in e or 'n^2' in e:
        return '，通常来自双重循环或两两比较。'
    if 'n' in e:
        return '，因为主要流程对数据做了一次线性处理。'
    return '。'

def explain_space(expr: str) -> str:
    e = expr.replace(' ', '')
    if e in {'O(1)', 'O（1）'}:
        return '，因为只使用常数级额外变量。'
    if 'n' in e or 'm' in e or 'k' in e:
        return '，额外空间主要来自哈希表/队列/递归栈等辅助结构。'
    return '。'

for path in Path('docs').glob('*.md'):
    text = path.read_text(encoding='utf-8')
    lines = text.splitlines()

    # 1) locate existing complexity section
    try:
        cidx = lines.index('### 复杂度分析')
    except ValueError:
        continue

    # capture complexity block until next header
    end = len(lines)
    for i in range(cidx + 1, len(lines)):
        if lines[i].startswith('## ') or lines[i].startswith('### '):
            end = i
            break

    block = [ln for ln in lines[cidx + 1:end]]
    while block and block[0].strip() == '':
        block.pop(0)
    while block and block[-1].strip() == '':
        block.pop()

    # 2) rewrite block lines with short explanations when missing
    new_block = []
    for ln in block:
        s = ln.strip()
        if not s:
            new_block.append('')
            continue

        # Bold format
        m1 = re.match(r'^(\*\*时间复杂度\*\*：\s*)(O\([^)]*\))(.*)$', s)
        m2 = re.match(r'^(\*\*空间复杂度\*\*：\s*)(O\([^)]*\))(.*)$', s)
        m3 = re.match(r'^(时间复杂度：\s*)(O\([^)]*\))(.*)$', s)
        m4 = re.match(r'^(空间复杂度：\s*)(O\([^)]*\))(.*)$', s)

        if m1:
            prefix, expr, tail = m1.groups()
            tail = tail.strip()
            if not tail:
                s = f"{prefix}{expr}{explain_time(expr)}"
        elif m2:
            prefix, expr, tail = m2.groups()
            tail = tail.strip()
            if not tail:
                s = f"{prefix}{expr}{explain_space(expr)}"
        elif m3:
            prefix, expr, tail = m3.groups()
            tail = tail.strip()
            if not tail:
                s = f"{prefix}{expr}{explain_time(expr)}"
        elif m4:
            prefix, expr, tail = m4.groups()
            tail = tail.strip()
            if not tail:
                s = f"{prefix}{expr}{explain_space(expr)}"
        new_block.append(s)

    # 3) remove old section
    new_lines = lines[:cidx] + lines[end:]

    # 4) insert after code block(s): right after the final ``` fence
    insert_at = None
    for i in range(len(new_lines) - 1, -1, -1):
        if new_lines[i].strip().startswith('```'):
            insert_at = i + 1
            break
    if insert_at is None:
        try:
            insert_at = new_lines.index('## 代码') + 1
        except ValueError:
            insert_at = len(new_lines)

    section = ['','### 复杂度分析',''] + new_block + ['']
    new_lines = new_lines[:insert_at] + section + new_lines[insert_at:]

    # normalize multiple blank lines
    norm = []
    blank = 0
    for ln in new_lines:
        if ln.strip() == '':
            blank += 1
            if blank <= 2:
                norm.append('')
        else:
            blank = 0
            norm.append(ln)

    out = '\n'.join(norm).rstrip() + '\n'
    if out != text:
        path.write_text(out, encoding='utf-8')
