from pathlib import Path
import re

reason_markers = ('因为', '主要', '来自', '需要', '最坏', '其中', '由', '由于')

def infer_reason(expr: str, kind: str) -> str:
    e = expr.replace(' ', '')
    if kind == 'time':
        if 'log' in expr:
            return '，主要开销来自排序/二分/堆等对数级操作。'
        if 'n³' in e or 'n^3' in e:
            return '，通常来自三重循环或三维状态转移。'
        if 'n²' in e or 'n^2' in e:
            return '，通常来自双重循环或两两比较。'
        if 'mn' in e or ('m' in e and 'n' in e and ('*' in e or '×' in e)):
            return '，因为需要遍历二维规模数据。'
        if 'O(1)' in expr:
            return '，因为核心操作与输入规模无关。'
        if 'n' in e:
            return '，因为主要流程对数据做了一次线性处理。'
        return '。'
    else:
        if 'O(1)' in expr:
            return '，因为只使用常数级额外变量。'
        return '，额外空间主要来自哈希表/队列/递归栈等辅助结构。'

for path in Path('docs').glob('*.md'):
    text = path.read_text(encoding='utf-8')
    lines = text.splitlines()
    out = []
    changed = False

    for line in lines:
        s = line

        # split one line containing both
        if '时间复杂度' in s and '空间复杂度' in s and s.find('时间复杂度') < s.find('空间复杂度'):
            idx = s.find('空间复杂度')
            first = s[:idx].rstrip(' ，')
            second = s[idx:].lstrip(' ，')
            for part in (first, second):
                out.append(part)
            changed = True
            continue

        # time line patterns
        mt = re.match(r'^(\*\*时间复杂度\*\*：\s*)(O\([^)]*\))(.*)$', s)
        if not mt:
            mt = re.match(r'^(时间复杂度：\s*)(O\([^)]*\))(.*)$', s)
        if mt:
            prefix, expr, tail = mt.groups()
            tail_s = tail.strip()
            if not any(m in tail_s for m in reason_markers):
                s = f"{prefix}{expr}{infer_reason(expr, 'time')}"
                changed = True
            out.append(s)
            continue

        # space line patterns
        ms = re.match(r'^(\*\*空间复杂度\*\*：\s*)(O\([^)]*\))(.*)$', s)
        if not ms:
            ms = re.match(r'^(空间复杂度：\s*)(O\([^)]*\))(.*)$', s)
        if ms:
            prefix, expr, tail = ms.groups()
            tail_s = tail.strip()
            if not any(m in tail_s for m in reason_markers):
                s = f"{prefix}{expr}{infer_reason(expr, 'space')}"
                changed = True
            out.append(s)
            continue

        out.append(s)

    if changed:
        path.write_text('\n'.join(out).rstrip() + '\n', encoding='utf-8')
